function createHandler({ tableName, dynamoDbClient }) {
	return async function handler(event) {
		const body = parseBody(event);
		const customerId = body.customerId ?? body.paymentId ?? `customer-${Date.now()}`;
		const message = body.message ?? "created";
		await dynamoDbClient.send(new import_dist_cjs.PutItemCommand({
			TableName: tableName,
			Item: {
				customerId: { S: customerId },
				message: { S: message }
			}
		}));
		return {
			statusCode: 200,
			body: JSON.stringify({
				customerId,
				stored: true
			})
		};
	};
}
